    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class, UnsupportedOperationException::class, ClientException::class, ServerException::class)
    fun getPermissionForUserForBankAccount(bankid: kotlin.String, accountid: kotlin.String, provider: kotlin.String, providerid: kotlin.String) : GetPermissionForUserForBankAccount200Response {
        val localVarResponse = getPermissionForUserForBankAccountWithHttpInfo(bankid = bankid, accountid = accountid, provider = provider, providerid = providerid)

        return when (localVarResponse.responseType) {
            ResponseType.Success -> (localVarResponse as Success<*>).data as GetPermissionForUserForBankAccount200Response
            ResponseType.Informational -> throw UnsupportedOperationException("Client does not support Informational responses.")
