            path = "/obp/v3.0.0/banks/{bankid}/accounts/{accountid}/permissions/{provider}/{providerid}".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())).replace("{"+"provider"+"}", encodeURIComponent(provider.toString())).replace("{"+"providerid"+"}", encodeURIComponent(providerid.toString())),
