    fun getPermissionsForBankAccount(bankid: kotlin.String, accountid: kotlin.String) : GetPermissionsForBankAccount200Response {
        val localVarResponse = getPermissionsForBankAccountWithHttpInfo(bankid = bankid, accountid = accountid)

        return when (localVarResponse.responseType) {
