     * @throws IllegalStateException If the request is not correctly configured
     * @throws IOException Rethrows the OkHttp execute method exception
     */
    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class)
    fun getPermissionsForBankAccountWithHttpInfo(bankid: kotlin.String, accountid: kotlin.String) : ApiResponse<GetPermissionsForBankAccount200Response?> {
        val localVariableConfig = getPermissionsForBankAccountRequestConfig(bankid = bankid, accountid = accountid)

        return request<Unit, GetPermissionsForBankAccount200Response>(
            localVariableConfig
        )
    }

    /**
     * To obtain the request config of the operation getPermissionsForBankAccount
     *
     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @return RequestConfig
     */
    fun getPermissionsForBankAccountRequestConfig(bankid: kotlin.String, accountid: kotlin.String) : RequestConfig<Unit> {
        val localVariableBody = null
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.GET,
            path = "/obp/v2.0.0/banks/{bankid}/accounts/{accountid}/permissions".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())),
            query = localVariableQuery,
            headers = localVariableHeaders,
            requiresAuthentication = true,
            body = localVariableBody
        )
    }

    /**
     * GET /obp/v6.0.0/banks/{bankid}/accounts/{accountid}/{viewid}/account
     * Get Account by Id (Full)
