     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @param viewid The VIEWID identifier
     * @param updateViewForBankAccountRequest Request body
     * @return ApiResponse<CreateUserWithAccountAccessById200ResponseHead?>
     * @throws IllegalStateException If the request is not correctly configured
     * @throws IOException Rethrows the OkHttp execute method exception
     */
    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class)
    fun updateViewForBankAccountWithHttpInfo(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, updateViewForBankAccountRequest: UpdateViewForBankAccountRequest) : ApiResponse<CreateUserWithAccountAccessById200ResponseHead?> {
        val localVariableConfig = updateViewForBankAccountRequestConfig(bankid = bankid, accountid = accountid, viewid = viewid, updateViewForBankAccountRequest = updateViewForBankAccountRequest)

        return request<UpdateViewForBankAccountRequest, CreateUserWithAccountAccessById200ResponseHead>(
            localVariableConfig
        )
    }

    /**
     * To obtain the request config of the operation updateViewForBankAccount
     *
     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @param viewid The VIEWID identifier
     * @param updateViewForBankAccountRequest Request body
     * @return RequestConfig
     */
    fun updateViewForBankAccountRequestConfig(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, updateViewForBankAccountRequest: UpdateViewForBankAccountRequest) : RequestConfig<UpdateViewForBankAccountRequest> {
        val localVariableBody = updateViewForBankAccountRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.PUT,
            path = "/obp/v3.0.0/banks/{bankid}/accounts/{accountid}/views/{viewid}".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())).replace("{"+"viewid"+"}", encodeURIComponent(viewid.toString())),
            query = localVariableQuery,
            headers = localVariableHeaders,
            requiresAuthentication = true,
            body = localVariableBody
        )
    }


    private fun encodeURIComponent(uriComponent: kotlin.String): kotlin.String =
        HttpUrl.Builder().scheme("http").host("localhost").addPathSegment(uriComponent).build().encodedPathSegments[0]
}
